user_name = #{userName}, nick_name = #{nickName}, openid = #{openid}, email = #{email}, phone = #{phone}, avatar = #{avatar}, password = #{password}, login_ip = #{loginIp}, login_date = #{loginDate}, update_user = #{updateUser}, remark = #{remark}, user_type = #{userType}, update_time = sysdate()
where user_id = #{userId}

