nick_name = #{nickName}, phone = #{phone}, openid = #{openid}, avatar = #{avatar}, password = #{password}, update_user = #{updateUser}, update_time = sysdate()
where user_id = #{userId}

mapper.select:
select distinct u.user_id, u.user_name, u.nick_name, u.email, u.phone, u.status, u.create_time from sys_user u left join sys_role_user ur on u.user_id = ur.user_id left join sys_role r on r.role_id = ur.role_id where u.is_delete = 0 and r.role_id = #{roleId}
AND u.user_name like concat('%', #{userName}, '%')
AND u.phone like concat('%', #{phone}, '%')
